# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int armor = 0;
    public float damageMultiplier = 1.0f;

    void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(int baseDamage)
    {
        int actualDamage = CalculateDamage(baseDamage);
        currentHealth -= actualDamage;
        
        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Die();
        }
        
        Debug.Log("Took " + actualDamage + " damage. Health: " + currentHealth);
    }

    public int CalculateDamage(int baseDamage)
    {
        float damageReduction = armor * 0.5f;
        int finalDamage = Mathf.Max(1, baseDamage - (int)damageReduction);
        return finalDamage;
    }

    public void Heal(int amount)
    {
        currentHealth += amount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }
        Debug.Log("Healed " + amount + ". Health: " + currentHealth);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Added " + amount + " currency. Total: " + currency);
    }

    public void Die()
    {
        Debug.Log("Player died!");
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public int healthPotionPrice = 50;
    public int armorUpgradePrice = 100;
    public int damageBoostPrice = 150;
    public int maxHealthUpgradePrice = 200;
    public int premiumCurrencyPrice = 500;

    public int healthPotionHealAmount = 50;
    public int armorUpgradeAmount = 5;
    public float damageBoostAmount = 0.2f;
    public int maxHealthUpgradeAmount = 20;
    public int premiumCurrencyAmount = 1000;

    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }

    public bool PurchaseHealthPotion()
    {
        int price = CalculateHealthPotionPrice();
        
        if (playerStats.currency >= price)
        {
            playerStats.currency -= price;
            playerStats.Heal(healthPotionHealAmount);
            Debug.Log("Purchased Health Potion for " + price);
            return true;
        }
        
        Debug.Log("Not enough currency for Health Potion");
        return false;
    }

    public bool PurchaseArmorUpgrade()
    {
        int price = CalculateArmorUpgradePrice();
        
        if (playerStats.currency >= price)
        {
            playerStats.currency -= price;
            playerStats.armor += armorUpgradeAmount;
            Debug.Log("Purchased Armor Upgrade for " + price + ". Armor: " + playerStats.armor);
            return true;
        }
        
        Debug.Log("Not enough currency for Armor Upgrade");
        return false;
    }

    public bool PurchaseDamageBoost()
    {
        int price = CalculateDamageBoostPrice();
        
        if (playerStats.currency >= price)
        {
            playerStats.currency -= price;
            playerStats.damageMultiplier += damageBoostAmount;
            Debug.Log("Purchased Damage Boost for " + price + ". Multiplier: " + playerStats.damageMultiplier);
            return true;
        }
        
        Debug.Log("Not enough currency for Damage Boost");
        return false;
    }

    public bool PurchaseMaxHealthUpgrade()
    {
        int price = CalculateMaxHealthUpgradePrice();
        
        if (playerStats.currency >= price)
        {
            playerStats.currency -= price;
            playerStats.maxHealth += maxHealthUpgradeAmount;
            playerStats.currentHealth += maxHealthUpgradeAmount;
            Debug.Log("Purchased Max Health Upgrade for " + price + ". Max Health: " + playerStats.maxHealth);
            return true;
        }
        
        Debug.Log("Not enough currency for Max Health Upgrade");
        return false;
    }

    public bool PurchasePremiumCurrency()
    {
        playerStats.AddCurrency(premiumCurrencyAmount);
        Debug.Log("Purchased Premium Currency Package");
        return true;
    }

    public int CalculateHealthPotionPrice()
    {
        return healthPotionPrice;
    }

    public int CalculateArmorUpgradePrice()
    {
        int level = playerStats.armor / armorUpgradeAmount;
        return armorUpgradePrice + (level * 25);
    }

    public int CalculateDamageBoostPrice()
    {
        int level = (int)((playerStats.damageMultiplier - 1.0f) / damageBoostAmount);
        return damageBoostPrice + (level * 50);
    }

    public int CalculateMaxHealthUpgradePrice()
    {
        int level = (playerStats.maxHealth - 100) / maxHealthUpgradeAmount;
        return maxHealthUpgradePrice + (level * 75);
    }
}

public class Enemy : MonoBehaviour
{
    public int baseDamage = 20;
    public PlayerStats player;

    void Start()
    {
        if (player == null)
        {
            player = FindObjectOfType<PlayerStats>();
        }
    }

    public void AttackPlayer()
    {
        if (player != null)
        {
            player.TakeDamage(baseDamage);
        }
    }

    public void TakeDamage(int damage)
    {
        int actualDamage = (int)(damage * FindObjectOfType<PlayerStats>().damageMultiplier);
        Debug.Log("Enemy took " + actualDamage + " damage");
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public Shop shop;

    void Start()
    {
        playerStats.AddCurrency(1000);
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            shop.PurchaseHealthPotion();
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            shop.PurchaseArmorUpgrade();
        }
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            shop.PurchaseDamageBoost();
        }
        if (Input.GetKeyDown(KeyCode.Alpha4))
        {
            shop.PurchaseMaxHealthUpgrade();
        }
        if (Input.GetKeyDown(KeyCode.Alpha5))
        {
            shop.PurchasePremiumCurrency();
        }
        if (Input.GetKeyDown(KeyCode.Space))
        {
            playerStats.TakeDamage(25);
        }
    }
}